SELECT 
    id, credit_mall_id, school_id, student_id, user_id, 
    num, credit, verify_state, verify_staff, verify_time, verify_remark
FROM credit_exchange


        AND credit_mall_id IN (SELECT id FROM credit_mall WHERE name LIKE CONCAT('%', #{query.giftName}, '%'))


        AND verify_state = #{query.verifyState}


        AND DATE(add_time) >= #{query.startDate}


        AND DATE(add_time) <= #{query.endDate}


ORDER BY add_time DESC
LIMIT #{query.pageSize} OFFSET ${(query.pageIndex - 1) * query.pageSize}

SELECT COUNT(*) FROM credit_exchange


        AND credit_mall_id IN (SELECT id FROM credit_mall WHERE name LIKE CONCAT('%', #{query.giftName}, '%'))


        AND verify_state = #{query.verifyState}


        AND DATE(add_time) >= #{query.startDate}


